// Convergence point for both retrieval branches. Normalizes whichever source ran
// into a single numbered block the model can cite from. For CourtListener it grounds
// the top-ranked result on its full opinion text (fetched in the prior step), windowed
// to the passage matching the question; remaining results fall back to the search
// snippet. For CanLII it uses the case plus its citator network.
const cfg = $('Set research configuration').first().json;
const max = Number(cfg.resultCount) || 5;
const maxSnip = Number(cfg.maxSnippetChars) || 500;
const q = $('Submit a legal question').first().json['Your legal question or issue'] || '';
const dbChoice = $('Submit a legal question').first().json['Source database'] || '';
const isCourtListener = dbChoice.includes('CourtListener');

let sources = [];
let retrievedFrom = '';

if (isCourtListener) {
  retrievedFrom = 'CourtListener';
  const results = ($('Search CourtListener case law').first().json.results || []).slice(0, max);
  // Full text of the top-ranked opinion, fetched by id in the prior node.
  const fetched = $json || {};
  const topId = Number(fetched.id);
  const topFull = fetched.plain_text || fetched.html || '';
  // Keyword set from the question, used to window the relevant passage of the opinion.
  const stop = new Set(['the','and','for','what','is','are','was','were','a','an','of','in','to','on','with','that','this','federal','court','courts','case','cases','law','laws','standard','question','issue','under']);
  const keywords = q.toLowerCase().split(/[^a-z]+/).filter(w => w.length > 3 && !stop.has(w));
  const windowText = (text) => {
    const clean = String(text || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    if (!clean) return '';
    const lower = clean.toLowerCase();
    let pos = -1;
    for (const k of keywords) { const p = lower.indexOf(k); if (p !== -1 && (pos === -1 || p < pos)) pos = p; }
    if (pos === -1) return clean.slice(0, 1500);
    const start = Math.max(0, pos - 200);
    const end = Math.min(clean.length, start + 1500);
    return (start > 0 ? '...' : '') + clean.slice(start, end) + (end < clean.length ? '...' : '');
  };
  sources = results.map((r, i) => {
    const op = Array.isArray(r.opinions) && r.opinions[0] ? r.opinions[0] : {};
    const full = (Number(op.id) === topId) ? topFull : '';
    const excerpt = full
      ? windowText(full)
      : String(op.snippet || r.snippet || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, maxSnip);
    return {
      index: i + 1,
      caseName: r.caseName || r.case_name || 'Unknown case',
      citation: Array.isArray(r.citation) ? r.citation.join('; ') : (r.citation || ''),
      court: r.court || r.court_id || '',
      date: r.dateFiled || r.date_filed || '',
      url: r.absolute_url ? ('https://www.courtlistener.com' + r.absolute_url) : '',
      snippet: excerpt
    };
  });
} else {
  retrievedFrom = 'CanLII';
  let caseMeta = {};
  try { caseMeta = $('Fetch CanLII case metadata').first().json || {}; } catch (e) { caseMeta = {}; }
  const citator = $json || {};
  const citing = citator.citingCases || citator.citedCases || citator.citedLegislations || [];
  sources.push({
    index: 1,
    caseName: caseMeta.title || 'Selected Canadian authority',
    citation: caseMeta.citation || '',
    court: caseMeta.databaseId || '',
    date: caseMeta.decisionDate || '',
    url: caseMeta.url || '',
    snippet: 'Primary authority selected by the user.'
  });
  citing.slice(0, Math.max(0, max - 1)).forEach((c, i) => {
    sources.push({
      index: i + 2,
      caseName: c.title || 'Related case',
      citation: c.citation || '',
      court: c.databaseId || '',
      date: c.decisionDate || '',
      url: c.url || '',
      snippet: 'Case linked to the primary authority through the CanLII citator.'
    });
  });
}

const lines = sources.map(s =>
  '[' + s.index + '] ' + s.caseName +
  ' | Citation: ' + (s.citation || 'n/a') +
  ' | Court: ' + (s.court || 'n/a') +
  ' | Date: ' + (s.date || 'n/a') +
  ' | URL: ' + (s.url || 'n/a') +
  '\nExcerpt: ' + (s.snippet || 'n/a')
).join('\n\n');
const groundingContext = sources.length ? lines : 'NO SOURCES WERE RETRIEVED.';

return [{ json: {
  question: q,
  sources,
  groundingContext,
  sourceCount: sources.length,
  retrievedFrom
} }];

const err = ($json.error && ($json.error.message || $json.error)) || 'A retrieval step failed.';
const disclaimer = $('Set research configuration').first().json.disclaimer
  || 'Research assistance only. This is not legal advice.';
const html = '<div style="font-family:system-ui,Segoe UI,Arial,sans-serif;max-width:720px;line-height:1.55;">' +
  '<h3>The legal database could not be reached</h3>' +
  '<p>The workflow could not retrieve sources, so no answer was generated. No case law is asserted.</p>' +
  '<p style="color:#555;font-size:0.85em;">Details: ' + String(err) + '</p>' +
  '<p>Check that the API credential is set and valid, that the CanLII database ID and case ID are correct in CanLII mode, and that you are within the API rate limits, then submit again.</p>' +
  '<hr><p style="color:#555;font-size:0.85em;">' + disclaimer + '</p>' +
  '</div>';
return [{ json: { html } }];

// Layer 2 of the anti-hallucination guardrail: deterministically verify every
// citation the model claimed against the retrieved sources, then render the result.
// A citation is valid only if its index maps to a source we actually retrieved, and
// we always render the source's own citation / name / url (never the model's strings),
// so a fabricated reporter cite or case name cannot reach the reader. The verification
// pass runs first and is kept separate from the grounding / prompt layer (layer 1).
const ai = $json.output || $json;
const ctx = $('Build grounding context').first().json;
const sources = ctx.sources || [];
const byIndex = new Map(sources.map(s => [Number(s.index), s]));
const claimed = Array.isArray(ai.citations) ? ai.citations : [];
const validated = [];
const dropped = [];
for (const c of claimed) {
  const src = byIndex.get(Number(c.index));
  if (!src) { dropped.push(c); continue; }
  validated.push({
    index: src.index,
    caseName: src.caseName,
    citation: src.citation,
    url: src.url,
    pinpoint: c.pinpoint || ''
  });
}
const supported = Boolean(ai.supported) && validated.length > 0;
const answer = supported
  ? String(ai.answer || '')
  : 'No supporting authority was found in the retrieved sources. The retrieved sources do not substantiate an answer to this question, so no case law is asserted. Try rephrasing the question, increasing the result count, or selecting a different source database.';
const caveats = String(ai.caveats || '');
const retrievedFrom = ctx.retrievedFrom;
const droppedCount = dropped.length;

// Render the cited answer for display.
const disclaimer = $('Set research configuration').first().json.disclaimer
  || 'Research assistance only. This is not legal advice. Read and verify every cited source before relying on it.';
const badge = supported
  ? '<span style="background:#1a7f37;color:#fff;padding:3px 10px;border-radius:4px;font-size:0.85em;">Supported by retrieved sources</span>'
  : '<span style="background:#b35900;color:#fff;padding:3px 10px;border-radius:4px;font-size:0.85em;">Not supported by retrieved sources</span>';
const cites = validated.map(c =>
  '<li>[' + c.index + '] <strong>' + c.caseName + '</strong>' +
  (c.citation ? ', ' + c.citation : '') +
  (c.pinpoint ? ' (' + c.pinpoint + ')' : '') +
  (c.url ? ' <a href="' + c.url + '" target="_blank" rel="noopener">view source</a>' : '') +
  '</li>'
).join('');
const citeBlock = cites
  ? '<h3>Verified citations</h3><ul>' + cites + '</ul>'
  : '<p><em>No verified citations were returned.</em></p>';
const note = droppedCount
  ? '<p style="color:#b35900;font-size:0.85em;">' + droppedCount + ' proposed citation(s) were dropped because they did not match any retrieved source.</p>'
  : '';
const answerHtml = answer.replace(/\n/g, '<br>');
const html = '<div style="font-family:system-ui,Segoe UI,Arial,sans-serif;max-width:720px;line-height:1.55;">' +
  '<p>' + badge + ' <span style="color:#555;font-size:0.85em;">Source: ' + (retrievedFrom || 'n/a') + '</span></p>' +
  '<h3>Answer</h3><p>' + answerHtml + '</p>' +
  citeBlock + note +
  (caveats ? '<h3>Caveats</h3><p>' + caveats + '</p>' : '') +
  '<hr><p style="color:#555;font-size:0.85em;">' + disclaimer + '</p>' +
  '</div>';

return [{ json: { html, supported, answer, validatedCitations: validated, droppedCount } }];
